Scripts.OnUpdate:
local cursorX, cursorY = GetCursorPosition();
local uiScale = UIParent:GetScale();
self:SetPoint("TOP", UIParent, "BOTTOMLEFT", cursorX / uiScale, cursorY / uiScale + 25);

Scripts.OnCursorChanged:
if not self:HasFocus() then return end
ScrollingEdit_SetCursorOffsets(self:GetParent(), y-65, h);
self:GetParent().handleCursorChange = true;

Scripts.OnLoad:
self:SetMinMaxValues(0, 100)
self:SetValue(0)
--self:SetScale(0.8)
self:SetStatusBarTexture(1, 1, 1, "BORDER", -1);
self:GetStatusBarTexture():SetGradient("VERTICAL", 8/255, 93/255, 72/255, 11/255, 136/255, 105/255);
self:SetStatusBarColor(0.2, 0.6, 1.0);

Scripts.OnEnter:
GameTooltip:SetOwner(self, "ANCHOR_BOTTOMRIGHT")
GameTooltip:SetText("Experience", 1, 1, 1);
GameTooltip:AddLine("Granted by DMs to reward players for participation.", nil, nil, nil, true);
GameTooltip:AddLine(self:GetValue().. " / 100", 1, 1, 1);
GameTooltip:Show();

Scripts.OnLoad:
self.scrollBar.trackBG:Hide()
self.scrollBar.doNotHide = true;
self.update = DiceMaster4.TraitEditor_StatsFrame_UpdateStats
self.dynamic = DiceMaster4.TraitEditor_StatsList_GetScrollFrameTopButton;
HybridScrollFrame_CreateButtons(self, "DiceMasterStatButtonTemplate");

Model_OnLoad(self);
self:SetCamDistanceScale(1.3);
hooksecurefunc(self, "SetDisplayInfo", DiceMaster4.PetEditor_SaveModel)

Scripts.OnEnter:
GameTooltip:SetOwner(self, "ANCHOR_RIGHT");
GameTooltip_SetTitle(GameTooltip, "Clean Up Inventory", HIGHLIGHT_FONT_COLOR);
GameTooltip_AddNormalLine(GameTooltip, "Auto-sorts your inventory to make room for new items.");
GameTooltip:Show();

Scripts.OnClick:
					HelpPlate_Hide( false );
					DiceMaster4.editor:SetWidth( 336 )
					DiceMasterTraitsFrame:SetPoint( "TOPLEFT", 10, -64 )
					DiceMasterTraitEditor.FormatBar:SetPoint( "BOTTOMLEFT", 20, 4 )
					DiceMaster4.editor.Inset:SetPoint("BOTTOMLEFT", 4, 40)
					DiceMaster4.editor.Bg:SetPoint("TOPLEFT", 0, -64)
					DiceMaster4.editor.Bg:SetPoint("BOTTOMRIGHT", -6, 40)
					DiceMaster4.editor.Inset:Show();
					DiceMaster4.editor.Bg:Show()
					PanelTemplates_SetTab(DiceMaster4.editor, 1);
                    DiceMasterTraitsFrame:Show();
                    -- DiceMasterTraitPicker:Show();
					DiceMasterTraitEditor.StatsWarning:Hide()
					DiceMasterTraitEditorExperienceBar:Hide()
					DiceMasterTraitEditor.FormatBar:Show();
					DiceMasterTraitEditorTraitsExpandButton:Show()
					DiceMasterTraitEditorTraitsExpandButton:SetExpanded( false )
